    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 20px;
}

.container {
    background: rgba(255, 255, 255, 0.95);
    border-radius: 20px;
    padding: 30px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
    max-width: 650px;
    width: 100%;
    text-align: center;
}

header h1 {
    color: #333;
    margin-bottom: 10px;
    font-size: 2.5em;
}

.subtitle {
    color: #666;
    font-size: 1.2em;
    margin-bottom: 30px;
}

.game-info {
    display: flex;
    justify-content: space-around;
    margin-bottom: 30px;
    flex-wrap: wrap;
    gap: 15px;
}

.info-card {
    background: linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%);
    border-radius: 15px;
    padding: 15px 25px;
    display: flex;
    align-items: center;
    gap: 15px;
    min-width: 150px;
    box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
}

.info-card i {
    font-size: 1.5em;
    color: #667eea;
}

.info-card .label {
    display: block;
    font-size: 0.9em;
    color: #666;
    margin-bottom: 5px;
}

.info-card .value {
    display: block;
    font-size: 1.5em;
    font-weight: bold;
    color: #333;
}

.game-container {
    position: relative;
    margin-bottom: 30px;
}

#gameCanvas {
    border: 4px solid #667eea;
    border-radius: 10px;
    background: #f0f0f0;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
    display: block;
    margin: 0 auto;
}

.overlay {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.8);
    border-radius: 10px;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    color: white;
    z-index: 10;
}

.overlay h2 {
    font-size: 2.5em;
    margin-bottom: 20px;
    color: #fff;
}

.overlay p {
    font-size: 1.2em;
    margin-bottom: 30px;
    color: #ddd;
}

.overlay span {
    color: #ff6b6b;
    font-weight: bold;
}

.controls {
    display: flex;
    justify-content: center;
    gap: 20px;
    flex-wrap: wrap;
}

.btn {
    padding: 12px 30px;
    border: none;
    border-radius: 25px;
    font-size: 1.1em;
    cursor: pointer;
    transition: all 0.3s ease;
    display: flex;
    align-items: center;
    gap: 10px;
    font-weight: 600;
}

.btn-primary {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    box-shadow: 0 4px 15px rgba(102, 126, 234, 0.4);
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(102, 126, 234, 0.6);
}

.btn-secondary {
    background: #f0f0f0;
    color: #333;
    border: 2px solid #ddd;
}

.btn-secondary:hover {
    background: #e0e0e0;
    border-color: #ccc;
}

footer {
    margin-top: 30px;
    color: #666;
    font-size: 0.9em;
}

footer p {
    margin: 5px 0;
}

/* 响应式设计 */
@media (max-width: 768px) {
    .container {
        padding: 20px;
    }

    header h1 {
        font-size: 2em;
    }

    .game-info {
        flex-direction: column;
        align-items: center;
    }

    .info-card {
        width: 100%;
        justify-content: center;
    }

    #gameCanvas {
        width: 100%;
        max-width: 400px;
        height: auto;
    }

    .controls {
        flex-direction: column;
        width: 100%;
    }

    .btn {
        width: 100%;
        justify-content: center;
    }
}

/* 动画效果 */
@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.overlay {
    animation: fadeIn 0.5s ease;
}

/* 网格线样式 */
.grid-line {
    stroke: #e0e0e0;
    stroke-width: 1;
}

